const msg = $input.first().json.message;
const text = (msg.text || '').trim();
const chatId = msg.chat.id;

// Route: /weight summary → summary, /weight <number> → log
const isSummary = /^\/weight\s+summary/i.test(text);
const isLog = /^\/weight\s+[\d.]+/i.test(text);

return [{ json: { text, chatId, isSummary, isLog } }];

const msg = $('Telegram Trigger').first().json.message;
const text = (msg.text || '').trim();
const chatId = msg.chat.id;

// Extract all numbers from the command: /weight <weight_kg> [height_cm]
const nums = [...text.matchAll(/[\d.]+/g)].map(m => parseFloat(m[0]));
if (nums.length === 0) {
  return [{ json: { error: true, chatId, reply: '❌ Please send your weight as a number.\nExample: `/weight 75.5` or `/weight 75.5 178`' } }];
}

const weight = nums[0];
if (weight < 20 || weight > 300) {
  return [{ json: { error: true, chatId, reply: '❌ Weight must be between 20 and 300 kg.' } }];
}

// Optional height (second number in message, must be 50–250 cm)
const heightRaw = nums[1];
const height_cm = (heightRaw && heightRaw >= 50 && heightRaw <= 250) ? heightRaw : null;

const now = new Date();
return [{ json: {
  error: false,
  chatId,
  weightId: 'w_' + now.getTime(),
  date: now.toLocaleDateString('en-CA', { timeZone: 'Asia/Kolkata' }),
  time: now.toLocaleTimeString('en-GB', { timeZone: 'Asia/Kolkata', hour12: false }),
  weight_kg: weight,
  height_cm
} }];

const w = $('Parse Weight').first().json;
const weight = w.weight_kg;

let bmiLine = '';
if (w.height_cm) {
  const h = w.height_cm / 100;
  const bmi = (weight / (h * h)).toFixed(1);
  let label = bmi < 18.5 ? 'Underweight' : bmi < 25 ? 'Normal' : bmi < 30 ? 'Overweight' : 'Obese';
  bmiLine = `\n\n💡 BMI: <b>${bmi}</b> (${label}) · based on ${w.height_cm} cm`;
}

const reply = `⚖️ <b>Weight Logged!</b>\n\n📅 ${w.date} at ${w.time.substring(0,5)}\n🏋️ <b>${weight} kg</b>${bmiLine}\n\n📊 /weight summary week  ·  /weight summary month`;

return [{ json: { reply } }];

const text = $('Telegram Trigger').first().json.message.text || '';
const chatId = $('Telegram Trigger').first().json.message.chat.id;

const isMonthly = /month/i.test(text);
const days = isMonthly ? 30 : 7;
const periodLabel = isMonthly ? 'Monthly (30 days)' : 'Weekly (7 days)';

// Parse optional height from command e.g. /weight summary week 178
const heightMatch = text.match(/(\d{2,3})\s*cm|(1[5-9]\d|2[0-4]\d)(?![\.\d])/);
const heightCm = heightMatch ? parseFloat(heightMatch[1] || heightMatch[2]) : null;

const today = new Date().toLocaleDateString('en-CA', { timeZone: 'Asia/Kolkata' });
const startDate = new Date();
startDate.setDate(startDate.getDate() - (days - 1));
const startDateStr = startDate.toLocaleDateString('en-CA', { timeZone: 'Asia/Kolkata' });

const allRows = $input.all();
const entries = allRows
  .filter(r => r.json.date >= startDateStr && r.json.date <= today && r.json.weight_kg)
  .map(r => ({ date: r.json.date, weight: parseFloat(r.json.weight_kg) }))
  .sort((a, b) => a.date.localeCompare(b.date));

if (entries.length === 0) {
  return [{ json: { chatId, reply: `⚖️ *${periodLabel} Weight Summary*\n\nNo weight entries found for this period.\n\nLog your weight with: \`/weight 75.5\`` } }];
}

const weights = entries.map(e => e.weight);
const minW = Math.min(...weights);
const maxW = Math.max(...weights);
const avgW = (weights.reduce((a, b) => a + b, 0) / weights.length).toFixed(1);
const firstW = weights[0];
const lastW = weights[weights.length - 1];
const change = (lastW - firstW).toFixed(1);
const changeSign = change > 0 ? '+' : '';
const changeEmoji = change < 0 ? '📉' : change > 0 ? '📈' : '➡️';

// Trend
let trend = '';
if (entries.length >= 4) {
  const firstHalf = weights.slice(0, Math.ceil(weights.length / 2));
  const lastHalf = weights.slice(Math.floor(weights.length / 2));
  const trendDiff = ((lastHalf.reduce((a,b)=>a+b,0)/lastHalf.length) - (firstHalf.reduce((a,b)=>a+b,0)/firstHalf.length)).toFixed(1);
  trend = `\n📊 Trend: ${trendDiff > 0 ? '+' : ''}${trendDiff} kg (${trendDiff < 0 ? 'losing' : trendDiff > 0 ? 'gaining' : 'stable'})`;
}

// BMI using current (latest) weight + height if provided
let bmiLine = '';
if (heightCm && heightCm >= 50 && heightCm <= 250) {
  const h = heightCm / 100;
  const bmi = (lastW / (h * h)).toFixed(1);
  const label = bmi < 18.5 ? 'Underweight' : bmi < 25 ? 'Normal weight' : bmi < 30 ? 'Overweight' : 'Obese';
  const bmiEmoji = bmi < 18.5 ? '🟡' : bmi < 25 ? '🟢' : bmi < 30 ? '🟠' : '🔴';
  const idealLow = (18.5 * h * h).toFixed(1);
  const idealHigh = (24.9 * h * h).toFixed(1);
  bmiLine = `\n\n📊 *BMI* (${lastW} kg @ ${heightCm} cm)\n${bmiEmoji} *${bmi}* — ${label}\n🎯 Ideal range: ${idealLow}–${idealHigh} kg`;
}

const recentList = entries.slice(-5).map(e => `  • ${e.date}: *${e.weight} kg*`).join('\n');

const dateRange = `${startDateStr} → ${today}`;
let msg = `⚖️ *${periodLabel} Weight Summary*\n_${dateRange}_\n\n`;
msg += `${changeEmoji} Change: *${changeSign}${change} kg* (${firstW} → ${lastW} kg)\n`;
msg += `📏 Range: ${minW} – ${maxW} kg | Avg: *${avgW} kg*`;
msg += trend;
msg += bmiLine;
msg += `\n\n📋 *Recent entries (${entries.length} total)*\n${recentList}`;

return [{ json: { chatId, reply: msg } }];
